def replace_cluj_names(text):
    """Replace all Cluj/Cluj-Napoca/village names with Pantelimon preserving case"""

    # List of place names to replace (case insensitive)
    place_names = [
        'Cluj-Napoca', 'Clujului', 'Clujului', 'Clujeni', 'clujeni', 
        'Clujean', 'clujean', 'Cluj', 'cluj', 'clujul', 'Clujul', 
        'clujului', 'Clujului',
        'Ciurila', 'Sălicea', 'Sălicea', 'Bușteni', 'Bucegi', 
        'Ciurila', 'Sălicea', 'Turda', 'Câmpia Turzii', 'Turda-Hotar', 
        'Petrilaca', 'Petrilacă', 'Petrilaca', 'Petrilacă', 'Hotar', 
        'Petrilaca', 'Hotar', 'Petrilacă', 'Petrilaca', 'Hotar Petrilaca', 
        'Petrilaca Hotar',
        'Mănăștur', 'Mănăștur', 'Gârbău', 'Midi', 'Munții Gutai', 'Muntii Gutai',
        'Iclod', 'Gherla', 'Satu Mare', 'Marriot', 'București', 'Bucuresti',
        'Argeș', 'Arges', 'Mehedinți', 'Mehedinti'
    ]

    # Sort by length descending to match longer names first
    place_names.sort(key=len, reverse=True)

    def replace_preserving_case(text, old, new):
        def replacer(match):
            matched = match.group(0)
            # Determine case pattern
            if matched.isupper():
                return new.upper()
            elif matched[0].isupper() and matched[1:].islower():
                return new.capitalize()
            elif matched.islower():
                return new.lower()
            else:
                # Mixed case - try to preserve pattern
                result = ''
                for i, c in enumerate(matched):
                    if i < len(new):
                        if c.isupper():
                            result += new[i].upper()
                        else:
                            result += new[i].lower()
                    else:
                        break
                return result
        pattern = re.compile(re.escape(old), re.IGNORECASE)
        return pattern.sub(replacer, text)

    result = text
    for place in place_names:
        result = replace_preserving_case(result, place, 'Pantelimon')

    return result

def add_video_foto_sarcasm(title, content):
    """Add sarcastic VIDEO/FOTO/AUDIO mentions to title/content"""
    has_video = bool(re.search(r'\b(VIDEO|VIDEO\.|VIDEO:)\b', title + ' ' + content, re.IGNORECASE))
    has_foto = bool(re.search(r'\b(FOTO|FOTO\.|FOTO:)\b', title + ' ' + content, re.IGNORECASE))
    has_audio = bool(re.search(r'\b(AUDIO|AUDIO\.|AUDIO:)\b', title + ' ' + content, re.IGNORECASE))
    has_vezi_video = bool(re.search(r'\b(VEZI\s+VIDEO|VEZI\s+VIDEO)\b', title + ' ' + content, re.IGNORECASE))

    new_title = title
    new_content = content

    # Remove existing VIDEO./FOTO./AUDIO. prefixes from title for cleaner handling
    new_title = re.sub(r'^(VIDEO\.|FOTO\.|AUDIO\.|VIDEO:|FOTO:|AUDIO:)\s*', '', new_title, flags=re.IGNORECASE)

    sarcasm_parts = []
    if has_video or has_vezi_video:
        sarcasm_parts.append('VIDEO')
    if has_foto:
        sarcasm_parts.append('FOTO')
    if has_audio:
        sarcasm_parts.append('AUDIO')

    if sarcasm_parts:
        sarcasm_str = ' și '.join(sarcasm_parts)
        # Add sarcastic mention to title
        new_title = f"{new_title} - {sarcasm_str}, pentru că nu-i suficient că s-a întâmplat"
        # Add to content too
        if not any(s.lower() in new_content.lower() for s in sarcasm_parts):
            new_content = f"{new_content} Un eveniment documentat cu {sarcasm_str.lower()}, pentru că realitatea nu-i suficient de convință."

    return new_title, new_content

