    title = title.replace('ă', 'ă').replace('â', 'â').replace('î', 'î').replace('ș', 'ș').replace('ț', 'ț')
    content = content.replace('Ă', 'Ă').replace('Â', 'Â').replace('Î', 'Î').replace('Ș', 'Ș').replace('Ț', 'Ț')
    content = content.replace('ă', 'ă').replace('â', 'â').replace('î', 'î').replace('ș', 'ș').replace('ț', 'ț')

    # Add sarcastic VIDEO/FOTO mentions
    title, content = add_video_foto_sarcasm(title, content)

    # Ensure title is catchy and short
    if len(title) > 120:
        title = title[:117] + '...'

    processed_articles.append({"title": title, "content": content})

